package com.agrios.platform.workmanagement.application;
import com.agrios.platform.inventory.domain.*; import com.agrios.platform.operations.domain.*; import com.agrios.platform.tasks.domain.*; import com.agrios.platform.workmanagement.api.WorkManagementDtos; import java.math.BigDecimal; import java.time.*; import java.util.*; import java.util.stream.*; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional;
@Service public class WorkManagementQueryService {private static final Set<String> ACTIVE=Set.of("OPEN","ASSIGNED","IN_PROGRESS","DEFERRED");private final TaskRepository tasks;private final FarmOperationRepository operations;private final InventoryItemRepository items;private final InventoryLotRepository lots;public WorkManagementQueryService(TaskRepository t,FarmOperationRepository o,InventoryItemRepository i,InventoryLotRepository l){tasks=t;operations=o;items=i;lots=l;}
 @Transactional(readOnly=true) public List<WorkManagementDtos.CalendarEntry> calendar(UUID tenant,Instant from,Instant to){var result=new ArrayList<WorkManagementDtos.CalendarEntry>();tasks.findByTenantIdAndDueAtBetweenOrderByDueAt(tenant,from,to).forEach(t->result.add(new WorkManagementDtos.CalendarEntry("TASK",t.id(),t.title(),t.status(),t.priority(),t.dueAt(),t.dueAt(),t.cropCycleId(),t.ownerEntityId(),"TASKS")));operations.findByTenantIdAndOperationDateBetweenOrderByOperationDate(tenant,from.atZone(ZoneOffset.UTC).toLocalDate(),to.atZone(ZoneOffset.UTC).toLocalDate()).forEach(o->{Instant at=o.operationDate().atStartOfDay().toInstant(ZoneOffset.UTC);result.add(new WorkManagementDtos.CalendarEntry("OPERATION",o.id(),o.operationType(),o.status(),"NORMAL",at,at,o.cropCycleId(),null,"OPERATIONS"));});return result.stream().sorted(Comparator.comparing(WorkManagementDtos.CalendarEntry::startsAt)).toList();}
 @Transactional(readOnly=true) public WorkManagementDtos.Dashboard dashboard(UUID tenant,UUID farmId,Instant now){var active=tasks.findByTenantIdAndStatusInOrderByDueAt(tenant,ACTIVE);LocalDate today=now.atZone(ZoneOffset.UTC).toLocalDate();long overdue=active.stream().filter(t->t.dueAt()!=null&&t.dueAt().isBefore(now)).count();long dueToday=active.stream().filter(t->t.dueAt()!=null&&t.dueAt().atZone(ZoneOffset.UTC).toLocalDate().equals(today)).count();var inventory=items.findByTenantIdAndFarmIdAndActiveTrueOrderByItemName(tenant,farmId);long low=inventory.stream().filter(InventoryItemEntity::lowStock).count();BigDecimal total=inventory.stream().map(InventoryItemEntity::currentQuantity).reduce(BigDecimal.ZERO,BigDecimal::add);long expiring=lots.findByTenantIdAndExpiryDateBetweenAndQuantityAvailableGreaterThanOrderByExpiryDateAsc(tenant,today,today.plusDays(30),BigDecimal.ZERO).size();long planned=operations.countByTenantIdAndStatus(tenant,"PLANNED");long progress=operations.countByTenantIdAndStatus(tenant,"IN_PROGRESS");return new WorkManagementDtos.Dashboard(active.size(),overdue,dueToday,planned,progress,low,expiring,total,calendar(tenant,now,now.plus(Duration.ofDays(14))).stream().limit(10).toList());}
}
